// Classify each email by urgency based on keywords in subject/body
// Returns: URGENT, NORMAL, or LOW

const items = $input.all();
const results = [];

const urgentKeywords = [
  'urgent', 'asap', 'emergency', 'immediately', 'critical',
  'help', 'broken', 'down', 'failure', 'refund', 'complaint',
  'dringend', 'sofort', 'notfall' // German keywords too
];

const lowKeywords = [
  'newsletter', 'unsubscribe', 'noreply', 'no-reply',
  'promotional', 'offer', 'discount', 'sale', 'subscribe'
];

for (const item of items) {
  const subject = (item.json.subject || '').toLowerCase();
  const body = (item.json.text || item.json.html || '').toLowerCase().slice(0, 500);
  const from = (item.json.from?.value?.[0]?.address || '').toLowerCase();
  const combined = subject + ' ' + body + ' ' + from;

  let priority = 'NORMAL';
  let reason = 'Standard email';

  if (urgentKeywords.some(kw => combined.includes(kw))) {
    priority = 'URGENT';
    reason = 'Contains urgent keyword';
  } else if (lowKeywords.some(kw => combined.includes(kw)) || from.includes('noreply')) {
    priority = 'LOW';
    reason = 'Likely promotional or automated';
  }

  results.push({
    json: {
      ...item.json,
      priority,
      priorityReason: reason,
      senderEmail: item.json.from?.value?.[0]?.address || '',
      senderName: item.json.from?.value?.[0]?.name || 'Valued Customer',
      receivedAt: new Date().toISOString()
    }
  });
}

return results;
